export interface ApiMembership {
  id: string;
  referenceType: string;
  referenceId: string;
  role: string;
  member: {
    id: string;
    displayName: string;
    email: string;
    type: string;
  };
}

export function isApiMembership(obj: any): obj is ApiMembership {
  return (
    obj &&
    typeof obj === 'object' &&
    'id' in obj &&
    'referenceType' in obj &&
    'referenceId' in obj &&
    'role' in obj &&
    'member' in obj &&
    obj.member &&
    typeof obj.member === 'object' &&
    'id' in obj.member &&
    'displayName' in obj.member &&
    'email' in obj.member &&
    'type' in obj.member
  );
}
